// ===== script: patch-grh-restore-original-v48 =====
(function(){
  'use strict';

  const ORIGINAL_GRH_B64 = '';

  function decodeB64Utf8(b64){
    const bin = atob(b64);
    const bytes = new Uint8Array(bin.length);
    for(let i=0;i<bin.length;i++) bytes[i] = bin.charCodeAt(i);
    return new TextDecoder('utf-8').decode(bytes);
  }

  const ORIGINAL_GRH_HTML = decodeB64Utf8(ORIGINAL_GRH_B64);

  function getView(){
    let v = document.getElementById('view-gestao-rh');
    if(!v){
      v = document.createElement('div');
      v.id = 'view-gestao-rh';
      v.className = 'page';
      (document.querySelector('.main-area') || document.body).appendChild(v);
    }
    return v;
  }

  function showOnlyGestao(){
    const v = getView();
    document.querySelectorAll('[id^="view-"]').forEach(el=>{
      if(el === v){ el.style.display='block'; el.classList.add('active'); }
      else{ el.style.display='none'; el.classList.remove('active'); }
    });
    v.style.display='block';
    v.classList.add('active');
    return v;
  }

  function ensureOriginalStructure(){
    const v = showOnlyGestao();
    if(!v.querySelector('#grh-tabs') || !v.querySelector('#grh-pane-colaboradores') || !v.querySelector('#grh-pane-enderecos')){
      v.innerHTML = ORIGINAL_GRH_HTML;
    }
    if(typeof window.__ensurePanelsGRH === 'function') window.__ensurePanelsGRH();
    ensureBackBar();
    return v;
  }

  function ensureBackBar(){
    const tabs = document.getElementById('grh-tabs');
    if(!tabs) return;
    let bar = document.getElementById('grh-back-bar');
    if(!bar){
      tabs.insertAdjacentHTML('afterend', `
        <div id="grh-back-bar" style="display:none;margin:0 0 14px;align-items:center;gap:12px;flex-wrap:wrap">
          <button class="grh-back-btn" type="button">← Voltar para Gestão de RH</button>
          <div class="grh-back-title" id="grh-back-title" style="display:none"></div>
        </div>
      `);
      bar = document.getElementById('grh-back-bar');
    }
    if(!document.getElementById('grh-module-hero')){
      bar.insertAdjacentHTML('afterend', '<div id="grh-module-hero" class="hero" style="display:none"></div>');
    }
    const btn = document.querySelector('#grh-back-bar .grh-back-btn');
    if(btn) btn.onclick = function(ev){ ev&&ev.preventDefault(); voltarGestaoRHSeguro(); return false; };
  }

  function hidePanes(){
    const v = getView();
    v.querySelectorAll('[id^="grh-pane-"]').forEach(p=>{
      p.style.display='none';
      p.classList.remove('active');
    });
  }

  function normalizeTab(tab){
    tab = String(tab||'').toLowerCase();
    if(tab==='endereco') tab='enderecos';
    if(tab==='beneficios') tab='beneficios-rh';
    if(tab==='pesquisas') tab='pesquisas-rh';
    if(tab==='roadmap') tab='roadmap-produto';
    return tab;
  }

  const titles = {
    colaboradores:'👥 Colaboradores',
    enderecos:'📍 Endereços',
    remuneracao:'💰 Remuneração',
    ferias:'🌴 Gestão de Férias',
    'beneficios-rh':'🎁 Benefícios',
    documentos:'📄 Documentos',
    'pesquisas-rh':'📋 Pesquisas',
    admissao:'📝 Admissão',
    desligamentos:'🚪 Desligamentos',
    movimentacoes:'🔄 Movimentações',
    'roadmap-produto':'🗺️ Roadmap do Produto'
  };

  function callRenderer(tab){
    try{
      if(tab==='colaboradores' && typeof window.grhRenderColabs==='function') window.grhRenderColabs();
      if(tab==='enderecos' && typeof window.grhRenderEnderecos==='function') window.grhRenderEnderecos();
      if(tab==='remuneracao'){
        // Use new premium v3 dashboard instead of old renderer
        if(typeof window.grhTab==='function'){
          window.grhTab('remuneracao');
        }
      }
      if(tab==='movimentacoes' && typeof window.grhRenderMovimentacoes==='function') window.grhRenderMovimentacoes();
      if(tab==='desligamentos' && typeof window.grhRenderDesligamentos==='function') window.grhRenderDesligamentos();
      if(tab==='admissao' && typeof window.grhRenderAdmissao==='function') window.grhRenderAdmissao();
      if(tab==='ferias'){
        if(typeof window.grhRenderFerias==='function') window.grhRenderFerias();
        else if(typeof window.renderRH==='function') window.renderRH();
      }
      if(tab==='beneficios-rh' && typeof window.grhRenderBeneficiosSaude==='function') window.grhRenderBeneficiosSaude();
      if(tab==='roadmap-produto' && typeof window.grhRenderRoadmap==='function') window.grhRenderRoadmap();
    }catch(e){ console.warn('[IMEX] render módulo', tab, e); }
  }

  function openModule(tab, btn){
    tab = normalizeTab(tab);
    const v = ensureOriginalStructure();
    v.classList.add('grh-module-open');
    const tabs = document.getElementById('grh-tabs');
    if(tabs) tabs.style.display='none';
    v.querySelectorAll(':scope > .hero, :scope > section.hero').forEach(function(el){ el.style.setProperty('display','none','important'); });
    v.querySelectorAll(':scope > .h-stats').forEach(function(el){ el.style.setProperty('display','none','important'); });
    /* Zero padding do wrapper interno que cria espaço em branco */
    v.querySelectorAll(':scope > div').forEach(function(el){ el.style.paddingTop='0'; });
    const bar = document.getElementById('grh-back-bar');
    if(bar){ bar.style.display='flex'; bar.style.marginBottom='6px'; }
    hidePanes();
    let pane = document.getElementById('grh-pane-'+tab);
    if(!pane && tab==='beneficios-rh') pane = document.getElementById('grh-pane-beneficios');
    if(!pane && tab==='pesquisas-rh') pane = document.getElementById('grh-pane-pesquisas');
    if(!pane && tab==='roadmap-produto') pane = document.getElementById('grh-pane-roadmap');
    if(pane){
      pane.style.display='block';
      pane.classList.add('active');
    }
    document.querySelectorAll('#grh-tabs .tab,#grh-tabs button').forEach(b=>b.classList.remove('active'));
    if(btn) btn.classList.add('active');
    const title = document.getElementById('grh-back-title');
    if(title) title.textContent = titles[tab] || 'Módulo';
    const _mhLabels = {
      colaboradores:'COLABORADORES', enderecos:'ENDEREÇOS', remuneracao:'REMUNERAÇÃO',
      ferias:'FÉRIAS', 'beneficios-rh':'BENEFÍCIOS', admissao:'ADMISSÃO',
      desligamentos:'DESLIGAMENTOS', movimentacoes:'MOVIMENTAÇÕES', 'roadmap-produto':'ROADMAP'
    };
    const _mhEye = {
      colaboradores:'Base de Colaboradores · RH', enderecos:'Cadastro de Endereços · RH',
      remuneracao:'Folha & Remuneração · RH', ferias:'Gestão de Férias · RH',
      'beneficios-rh':'Planos & Benefícios · RH', admissao:'Processo de Admissão · RH',
      desligamentos:'Desligamentos · RH', movimentacoes:'Movimentações · RH',
      'roadmap-produto':'Roadmap do Produto · RH'
    };
    const mhero = document.getElementById('grh-module-hero');
    if(mhero){
      if(tab !== 'documentos' && _mhLabels[tab]){
        mhero.innerHTML = '<div class="h-content"><div class="h-eyebrow">'+(_mhEye[tab]||'Gestão RH · Módulo')+'</div><h1>'+_mhLabels[tab]+'</h1></div>';
        mhero.style.setProperty('display','flex','important');
      } else {
        mhero.style.setProperty('display','none','important');
      }
    }
    callRenderer(tab);
    window.scrollTo({top:0,behavior:'smooth'});
    return false;
  }

  function hubHTML(){
    const cards = [
      ['👥','Colaboradores','Base cadastral completa, contratos, documentos, benefícios e histórico.','colaboradores'],
      ['📍','Endereços','Cadastro, comprovantes, pendências e atualização cadastral.','enderecos'],
      ['💰','Remuneração','Folha, salários médios, CLT/PJ e visão mensal.','remuneracao'],
      ['🌴','Férias','Saldo, períodos, aprovações, calendário e vencimentos.','ferias'],
      ['🎁','Benefícios','Planos, cartões, dependentes, regras e fornecedores.','beneficios-rh'],
      ['📄','Documentos','Políticas, processos, arquivos internos e comprovantes.','documentos'],
      ['📋','Pesquisas','Pesquisas internas, modelos, respostas e relatórios.','pesquisas-rh'],
      ['📝','Admissão','Checklist admissional, documentos e integração.','admissao'],
      ['🚪','Desligamentos','Controle de desligamentos, motivos e entrevistas de saída.','desligamentos'],
      ['🔄','Movimentações','Alterações de cargo, salário, setor e gestor.','movimentacoes'],
      ['🔐','Acessos e Permissões','Controle o que cada perfil pode ver e fazer no sistema.','acessos'],
      ['🗺️','Roadmap do Produto','Fases implantadas e próximas entregas do sistema.','roadmap-produto']
    ];
    return `
      <section class="hero" style="background:radial-gradient(at 18% 15%, #1d54d6 0%, transparent 48%), radial-gradient(at 85% 5%, #061535 0%, transparent 45%), radial-gradient(at 88% 92%, #1f7fe0 0%, transparent 55%), radial-gradient(at 5% 95%, #040d24 0%, transparent 45%), #0a1d4a!important">
        <div class="h-content"><div class="h-eyebrow">Painel exclusivo · RH</div><h1>GESTÃO DE RH</h1><p>Base centralizada de colaboradores, endereços, remuneração, férias, benefícios, documentos e movimentações.</p></div>
        <div class="h-stats"><div class="h-stat"><span class="h-num" id="hub-total-colabs">63</span><span class="h-lbl">Colaboradores</span></div><div class="h-stat"><span class="h-num" id="hub-total-clt">44</span><span class="h-lbl">CLT</span></div><div class="h-stat"><span class="h-num">19</span><span class="h-lbl">PJ</span></div></div>
      </section>
      <div class="imex-rh-grid-final" style="display:grid;grid-template-columns:repeat(3,minmax(240px,1fr));gap:18px;margin-bottom:22px">
        ${cards.map(c=>`<article class="imex-rh-card-final" data-rh-tab="${c[3]}" role="button" tabindex="0" style="background:#fff;border:1px solid var(--border);border-radius:22px;padding:22px;box-shadow:0 14px 34px rgba(16,24,40,.07);cursor:pointer;display:flex;flex-direction:column;gap:12px;min-height:210px;justify-content:space-between">
          <div><div style="width:52px;height:52px;border-radius:18px;background:#eef4ff;display:flex;align-items:center;justify-content:center;font-size:24px;margin-bottom:14px">${c[0]}</div><h3 style="font-size:18px;margin:0 0 8px;color:#111827">${c[1]}</h3><p style="font-size:13px;color:#64748b;line-height:1.5;margin:0">${c[2]}</p></div>
          <button type="button" class="btn btn-g imex-rh-open-final" data-rh-tab="${c[3]}" style="width:100%;justify-content:center;color:#0047FF;font-weight:900">Abrir módulo →</button>
        </article>`).join('')}
      </div>`;
  }

  function voltarGestaoRHSeguro(){
    const v = showOnlyGestao();
    v.classList.remove('grh-module-open');
    v.innerHTML = hubHTML();
    bindHubCards(v);
    window.scrollTo({top:0,behavior:'smooth'});
    return false;
  }

  function bindHubCards(scope){
    (scope || document).querySelectorAll('.conecta-rh-rh-card-final,.conecta-rh-rh-open-final').forEach(el=>{
      el.onclick = function(ev){
        if(ev){ ev.preventDefault(); ev.stopPropagation(); if(ev.stopImmediatePropagation) ev.stopImmediatePropagation(); }
        const root = el.closest('.conecta-rh-rh-card-final') || el;
        const tab = root.getAttribute('data-rh-tab') || el.getAttribute('data-rh-tab');
        return openModule(tab);
      };
      el.onkeydown = function(ev){ if(ev.key==='Enter'||ev.key===' '){ ev.preventDefault(); el.click(); } };
    });
  }

  // Render de Endereços com fallback claro quando a base ainda não possui endereço cadastrado.
  window.grhRenderEnderecos = async function(){
    const tbody = document.getElementById('grh-end-body');
    if(!tbody) return;
    try{
      const all = typeof window.grhGetColabs === 'function' ? await window.grhGetColabs(true) : [];
      const q = (document.getElementById('grh-end-search')?.value || '').toLowerCase();
      let dados = all;
      if(q) dados = dados.filter(c => [c.nome,c.email,c.setor,c.funcao].some(v => String(v||'').toLowerCase().includes(q)));
      const countEl = document.getElementById('grh-end-count');
      if(countEl) countEl.textContent = `${dados.length} colaboradores`;
      if(!dados.length){
        tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;padding:32px;color:var(--ink-60)">Nenhum colaborador encontrado.</td></tr>`;
        return;
      }
      tbody.innerHTML = dados.map(c=>{
        const e = c.endereco || {};
        const cep = e.cep || c.cep || 'Não informado';
        const rua = e.rua || c.rua || 'Não informado';
        const num = e.num || e.numero || c.num || c.numero || '—';
        const comp = e.comp || c.comp || '';
        const bairro = e.bairro || c.bairro || 'Não informado';
        const cidade = e.cidade || c.cidade || 'Não informado';
        const uf = e.uf || c.uf || '';
        const pendente = cep === 'Não informado' || rua === 'Não informado';
        return `<tr>
          <td style="padding-left:20px;font-weight:600">${c.nome || '—'}<br><small style="color:var(--ink-60)">${c.email || ''}</small></td>
          <td style="font-size:12px">${cep}</td>
          <td style="font-size:12px">${rua}</td>
          <td style="font-size:12px">${num} ${comp ? '('+comp+')' : ''}</td>
          <td style="font-size:12px">${bairro}</td>
          <td style="font-size:12px">${cidade}${uf ? ' / '+uf : ''}</td>
          <td style="white-space:nowrap"><span style="background:${pendente?'var(--g-orange-s)':'var(--g-green-s)'};color:${pendente?'#b45309':'#15803d'};border-radius:999px;padding:4px 8px;font-size:11px;font-weight:800">${pendente?'Pendente':'Atualizado'}</span> <button onclick="typeof grhAbrirModalEndereco==='function' ? grhAbrirModalEndereco('${c._id}') : alert('Editar endereço: ${(c.nome||'').replace(/'/g,'')}')" style="border:1px solid var(--border);background:#fff;border-radius:6px;padding:4px 8px;cursor:pointer;font-size:12px;margin-left:6px">📍 Editar</button></td>
        </tr>`;
      }).join('');
    }catch(e){
      tbody.innerHTML = `<tr><td colspan="7" style="text-align:center;padding:24px;color:var(--rust)">Erro ao carregar endereços: ${e.message}</td></tr>`;
    }
  };

  window.voltarGestaoRH = voltarGestaoRHSeguro;
  window.voltarParaGestaoRH = voltarGestaoRHSeguro;
  window.voltarMenuGestaoRH = voltarGestaoRHSeguro;
  window.renderGestaoRH = voltarGestaoRHSeguro;
  window.gestaoRhCarregar = async function(){
    try{ if(typeof window.grhImportarSeVazio==='function') await window.grhImportarSeVazio(); }catch(e){}
    return voltarGestaoRHSeguro();
  };

  const oldSbNav = window.sbNav;
  window.sbNav = function(id){
    const key = String(id||'').toLowerCase();
    if(key==='gestao-rh') return voltarGestaoRHSeguro();
    if(['colaboradores','enderecos','endereco','remuneracao'].includes(key)) return openModule(key);
    return typeof oldSbNav === 'function' ? oldSbNav.apply(this, arguments) : undefined;
  };

  const oldSwitchView = window.switchView;
  window.switchView = function(id){
    const key = String(id||'').toLowerCase();
    if(key==='gestao-rh') return voltarGestaoRHSeguro();
    if(['colaboradores','enderecos','endereco','remuneracao'].includes(key)) return openModule(key);
    return typeof oldSwitchView === 'function' ? oldSwitchView.apply(this, arguments) : (typeof window.sbNav==='function' ? window.sbNav(id) : undefined);
  };

  window.grhTab = function(tab, btn){ return openModule(tab, btn); };

  document.addEventListener('click', function(ev){
    const el = ev.target && ev.target.closest && ev.target.closest('button,a,.conecta-rh-rh-card-final,.conecta-rh-rh-open-final');
    if(!el) return;
    const txt = (el.innerText||el.textContent||'').toLowerCase();
    const on = (el.getAttribute('onclick')||'').toLowerCase();
    if(txt.includes('voltar para gestão') || txt.includes('voltar para gestao') || on.includes('voltargestaorh')){
      ev.preventDefault(); ev.stopPropagation(); if(ev.stopImmediatePropagation) ev.stopImmediatePropagation();
      voltarGestaoRHSeguro(); return false;
    }
  }, true);

  function boot(){
    const perfil = (typeof window.roleAtual === 'function' ? window.roleAtual() : ((sessionStorage.getItem('imexPreferredRole')||sessionStorage.getItem('role')||localStorage.getItem('role')||'colaborador').toLowerCase()));
    if(perfil === 'rh'){
      setTimeout(()=>{ voltarGestaoRHSeguro(); }, 450);
      setTimeout(()=>{ voltarGestaoRHSeguro(); }, 1200);
    }
  }
  if(document.readyState === 'loading') document.addEventListener('DOMContentLoaded', boot);
  else boot();
})();

